const express = require('express');

function installersRouter({ installerService }) {
  const r = express.Router();

  // GET /v1/installers/lookup?zip=48126
  r.get('/lookup', async (req, res, next) => {
    try {
      const zip = req.query.zip ? String(req.query.zip).trim() : null;
      const out = await installerService.lookupBestInstallerByZip(zip);
      res.json(out);
    } catch (e) {
      next(e);
    }
  });

  return r;
}

module.exports = { installersRouter };

const axios = require('axios');

class InstallerService {
  /**
   * @param {{db: import('pg').Pool, cacheTtlDays?:number}} deps
   */
  constructor({ db, cacheTtlDays = 30 }) {
    this.db = db;
    this.cacheTtlDays = cacheTtlDays;
    this.http = axios.create({ timeout: 15_000, headers: { Accept: 'application/json' } });
  }

  async _ensureTables() {
    await this.db.query({
      text: `
        create table if not exists installer (
          id uuid primary key,
          name text not null,
          address1 text,
          address2 text,
          city text,
          state text,
          zip text not null,
          phone text,
          website text,
          active boolean not null default true,
          lat numeric(9,6),
          lon numeric(9,6),
          created_at timestamptz not null default now(),
          updated_at timestamptz not null default now()
        );

        create index if not exists installer_active_idx on installer(active);
        create index if not exists installer_zip_idx on installer(zip);

        create table if not exists zip_geo (
          zip text primary key,
          lat numeric(9,6) not null,
          lon numeric(9,6) not null,
          city text,
          state text,
          country text,
          as_of timestamptz not null default now()
        );
      `
    });
  }

  async _getZipGeo(zip) {
    await this._ensureTables();
    const { rows } = await this.db.query({
      text: `select zip, lat, lon, as_of from zip_geo where zip = $1`,
      values: [zip]
    });
    return rows[0] || null;
  }

  _isFresh(asOf) {
    if (!asOf) return false;
    const t = new Date(asOf).getTime();
    if (!Number.isFinite(t)) return false;
    const ageMs = Date.now() - t;
    return ageMs >= 0 && ageMs <= this.cacheTtlDays * 24 * 60 * 60 * 1000;
  }

  async _fetchZipGeo(zip) {
    // US-only simple ZIP lookup. If you need CA/etc later, we can swap providers.
    // https://api.zippopotam.us/us/{zip}
    const url = `https://api.zippopotam.us/us/${encodeURIComponent(zip)}`;
    const res = await this.http.get(url);
    const data = res.data || {};
    const place = Array.isArray(data.places) ? data.places[0] : null;

    const lat = place?.latitude != null ? Number(place.latitude) : null;
    const lon = place?.longitude != null ? Number(place.longitude) : null;
    if (!Number.isFinite(lat) || !Number.isFinite(lon)) {
      const err = new Error('zip_geocode_failed');
      err.details = { zip, data };
      err.status = 400;
      throw err;
    }

    return {
      zip,
      lat,
      lon,
      city: place['place name'] || null,
      state: place['state abbreviation'] || null,
      country: data.country_abbreviation || null
    };
  }

  async getZipLatLon(zip) {
    const z = String(zip || '').trim();
    if (!z) {
      const err = new Error('zip_required');
      err.status = 400;
      throw err;
    }

    const cached = await this._getZipGeo(z);
    if (cached && this._isFresh(cached.as_of)) {
      return { zip: z, lat: Number(cached.lat), lon: Number(cached.lon) };
    }

    const fresh = await this._fetchZipGeo(z);

    await this.db.query({
      text: `
        insert into zip_geo (zip, lat, lon, city, state, country, as_of)
        values ($1, $2::numeric(9,6), $3::numeric(9,6), $4, $5, $6, now())
        on conflict (zip) do update set
          lat = excluded.lat,
          lon = excluded.lon,
          city = excluded.city,
          state = excluded.state,
          country = excluded.country,
          as_of = excluded.as_of
      `,
      values: [fresh.zip, fresh.lat, fresh.lon, fresh.city, fresh.state, fresh.country]
    });

    return { zip: z, lat: fresh.lat, lon: fresh.lon };
  }

  async lookupBestInstallerByZip(zip) {
    await this._ensureTables();

    const z = String(zip || '').trim();
    if (!z) {
      const err = new Error('zip_required');
      err.status = 400;
      throw err;
    }

    const origin = await this.getZipLatLon(z);

    const { rows } = await this.db.query({
      text: `
        select id, name, address1, address2, city, state, zip, phone, website, active,
               lat, lon
        from installer
        where active = true
          and lat is not null
          and lon is not null
      `
    });

    const best = rows
      .map((r) => {
        const d = haversineMiles(origin.lat, origin.lon, Number(r.lat), Number(r.lon));
        return { ...r, distanceMiles: d };
      })
      .sort((a, b) => a.distanceMiles - b.distanceMiles)[0];

    if (!best) return { installer: null };

    return {
      installer: {
        id: best.id,
        name: best.name,
        address1: best.address1,
        address2: best.address2,
        city: best.city,
        state: best.state,
        zip: best.zip,
        phone: best.phone,
        website: best.website,
        distanceMiles: round(best.distanceMiles, 2)
      }
    };
  }
}

function haversineMiles(lat1, lon1, lat2, lon2) {
  const R = 3958.8; // miles
  const toRad = (d) => (d * Math.PI) / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

function round(n, digits) {
  const p = Math.pow(10, digits);
  return Math.round(n * p) / p;
}

module.exports = { InstallerService };

require('dotenv').config();

const { loadConfig } = require('./config');
const { createPool } = require('./db/pool');
const { createApp } = require('./app');

const { VehicleService } = require('./services/VehicleService');
const { FitmentService } = require('./services/FitmentService');
const { WheelService } = require('./services/WheelService');
const { WheelSizeCatalogService } = require('./services/WheelSizeCatalogService');
const { TireService } = require('./services/TireService');
const { PackageEngineService } = require('./services/PackageEngineService');
const { TireSizeService } = require('./services/TireSizeService');
const { InstallerService } = require('./services/InstallerService');

const { WheelProsAdapter } = require('./adapters/wheelpros/WheelProsAdapter');
const { WheelSizeFitmentAdapter } = require('./adapters/fitment/WheelSizeFitmentAdapter');
const { TireConnectScrapeAdapter } = require('./adapters/tires/TireConnectScrapeAdapter');

async function main() {
  const config = loadConfig();
  const db = createPool({ databaseUrl: config.DATABASE_URL });

  const vehicleService = new VehicleService({ db });

  // Fitment provider (MVP: Wheel-Size API)
  const fitmentProvider = new WheelSizeFitmentAdapter({
    baseUrl: config.WHEEL_SIZE_BASE_URL,
    apiKey: config.WHEEL_SIZE_API_KEY
  });
  const fitmentService = new FitmentService({
    db,
    provider: fitmentProvider,
    cacheTtlDays: config.FITMENT_CACHE_TTL_DAYS
  });

  const wheelSizeCatalogService = new WheelSizeCatalogService({
    db,
    baseUrl: config.WHEEL_SIZE_BASE_URL,
    apiKey: config.WHEEL_SIZE_API_KEY,
    cacheTtlDays: config.FITMENT_CACHE_TTL_DAYS
  });

  // Wheel supplier (MVP: Wheel Pros)
  const wheelAdapter = new WheelProsAdapter({
    authBaseUrl: config.WHEELPROS_AUTH_BASE_URL,
    productsBaseUrl: config.WHEELPROS_PRODUCTS_BASE_URL,
    pricingBaseUrl: config.WHEELPROS_PRICING_BASE_URL,
    userName: config.WHEELPROS_USERNAME,
    password: config.WHEELPROS_PASSWORD,
    company: config.WHEELPROS_COMPANY,
    customer: config.WHEELPROS_CUSTOMER,
    currencyCode: config.WHEELPROS_CURRENCY
  });
  const tireSizeService = new TireSizeService();

  const wheelService = new WheelService({ db, wheelAdapter, tireSizeService });

  // Tire supplier (MVP: TireConnect scrape; persists into structured tables)
  const tireAdapter = (config.TIRECONNECT_WIDGET_ID && config.TIRECONNECT_LOCATION_ID)
    ? new TireConnectScrapeAdapter({
      widgetId: config.TIRECONNECT_WIDGET_ID,
      locationId: config.TIRECONNECT_LOCATION_ID,
      baseUrl: config.TIRECONNECT_BASE_URL,
      headless: true
    })
    : null;

  const tireService = new TireService({ db, tireAdapter, tireSizeService });

  const packageEngineService = new PackageEngineService({
    vehicleService,
    fitmentService,
    wheelService,
    tireService,
    tireSizeService
  });

  const installerService = new InstallerService({
    db,
    cacheTtlDays: config.FITMENT_CACHE_TTL_DAYS
  });

  const app = createApp({
    config,
    services: { vehicleService, fitmentService, wheelService, wheelSizeCatalogService, tireService, packageEngineService, installerService }
  });

  app.listen(config.PORT, () => {
    console.log(`WTD package engine listening on http://127.0.0.1:${config.PORT}`);
  });
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});

