import React, { useEffect, useState } from "react";

function App() {
  const [years, setYears] = useState([]);
  const [makes, setMakes] = useState([]);
  const [models, setModels] = useState([]);

  const [year, setYear] = useState("");
  const [make, setMake] = useState("");
  const [model, setModel] = useState("");

  const API = "http://127.0.0.1:8790/v1";

  useEffect(() => {
    fetch(`${API}/vehicles/years`)
      .then(r => r.json())
      .then(d => setYears(d.results || []));
  }, []);

  const loadMakes = async y => {
    setYear(y);
    const r = await fetch(`${API}/vehicles/makes?year=${y}`);
    const d = await r.json();
    setMakes(d.results || []);
  };

  const loadModels = async m => {
    setMake(m);
    const r = await fetch(`${API}/vehicles/models?year=${year}&make=${m}`);
    const d = await r.json();
    setModels(d.results || []);
  };

  return (
    <div style={{padding:40,fontFamily:"Arial"}}>
      <h1>Warehouse Tire Direct Sandbox</h1>

      <h3>Select Vehicle</h3>

      <div style={{display:"flex",gap:20}}>

        <select onChange={e=>loadMakes(e.target.value)}>
          <option>Year</option>
          {years.map(y=>(
            <option key={y}>{y}</option>
          ))}
        </select>

        <select onChange={e=>loadModels(e.target.value)}>
          <option>Make</option>
          {makes.map(m=>(
            <option key={m}>{m}</option>
          ))}
        </select>

        <select onChange={e=>setModel(e.target.value)}>
          <option>Model</option>
          {models.map(m=>(
            <option key={m}>{m}</option>
          ))}
        </select>

      </div>

      <br/>

      <div>
        <strong>Selected:</strong> {year} {make} {model}
      </div>

    </div>
  );
}

export default App;

