.page {
  padding: 40px;
  font-family: Arial, sans-serif;
  color: #111;
}

.title {
  margin: 0 0 18px 0;
}

.selectorRow {
  display: flex;
  gap: 12px;
  align-items: center;
  flex-wrap: wrap;
}

.selectorRow select {
  padding: 8px 10px;
  min-width: 160px;
}

.primaryBtn {
  padding: 9px 14px;
  border: 1px solid #222;
  background: #111;
  color: white;
  cursor: pointer;
  border-radius: 6px;
}

.primaryBtn:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.selectedRow {
  margin-top: 14px;
}

.errorBox {
  margin-top: 12px;
  padding: 10px 12px;
  border: 1px solid #b00020;
  background: #ffecec;
  color: #7a0016;
  border-radius: 6px;
}

.resultsHeader {
  margin-top: 18px;
  padding: 12px;
  border: 1px solid #ddd;
  border-radius: 8px;
  background: #fafafa;
  display: flex;
  gap: 18px;
  flex-wrap: wrap;
}

.grid {
  margin-top: 16px;
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 14px;
}

.card {
  border: 1px solid #ddd;
  border-radius: 10px;
  overflow: hidden;
  background: white;
  display: flex;
  flex-direction: column;
  min-height: 360px;
}

.imgWrap {
  height: 190px;
  background: #f4f4f4;
  display: flex;
  align-items: center;
  justify-content: center;
}

.imgWrap img {
  max-height: 100%;
  max-width: 100%;
  object-fit: contain;
}

.imgPlaceholder {
  color: #666;
  font-size: 13px;
}

.cardBody {
  padding: 12px;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.cardTitle {
  font-weight: 700;
  line-height: 1.25;
}

.meta {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px 10px;
  font-size: 13px;
}

.label {
  color: #666;
}

.empty {
  margin-top: 14px;
  color: #555;
}

