import React, { useEffect, useMemo, useState } from "react";
import "./App.css";

function App() {
  const [years, setYears] = useState([]);
  const [makes, setMakes] = useState([]);
  const [models, setModels] = useState([]);

  const [year, setYear] = useState("");
  const [make, setMake] = useState("");
  const [model, setModel] = useState("");

  const [loadingVehicle, setLoadingVehicle] = useState(false);
  const [loadingPackages, setLoadingPackages] = useState(false);
  const [error, setError] = useState(null);

  const [vehicle, setVehicle] = useState(null);
  const [recommendedTireSize, setRecommendedTireSize] = useState(null);
  const [wheelResults, setWheelResults] = useState([]);

  const API = "http://127.0.0.1:8790/v1";

  const isLoading = loadingVehicle || loadingPackages;

  const selectedLabel = useMemo(() => {
    const parts = [year, make, model].filter(Boolean);
    return parts.join(" ");
  }, [year, make, model]);

  useEffect(() => {
    (async () => {
      try {
        setError(null);
        const r = await fetch(`${API}/vehicles/years`);
        const d = await r.json();
        setYears(d.results || []);
      } catch (e) {
        setError(String(e));
      }
    })();
  }, []);

  const loadMakes = async (y) => {
    const yy = String(y || "").trim();
    setYear(yy);
    setMake("");
    setModel("");
    setMakes([]);
    setModels([]);

    // Reset results when the vehicle selection changes
    setVehicle(null);
    setRecommendedTireSize(null);
    setWheelResults([]);
    setError(null);

    if (!yy || yy === "Year") return;

    try {
      const r = await fetch(`${API}/vehicles/makes?year=${encodeURIComponent(yy)}`);
      const d = await r.json();
      if (!r.ok) throw new Error(d?.error || "failed_to_load_makes");
      setMakes(d.results || []);
    } catch (e) {
      setError(String(e?.message || e));
    }
  };

  const loadModels = async (m) => {
    const mm = String(m || "").trim();
    setMake(mm);
    setModel("");
    setModels([]);

    setVehicle(null);
    setRecommendedTireSize(null);
    setWheelResults([]);
    setError(null);

    if (!mm || mm === "Make") return;

    try {
      const r = await fetch(`${API}/vehicles/models?year=${encodeURIComponent(year)}&make=${encodeURIComponent(mm)}`);
      const d = await r.json();
      if (!r.ok) throw new Error(d?.error || "failed_to_load_models");
      setModels(d.results || []);
    } catch (e) {
      setError(String(e?.message || e));
    }
  };

  const onFindWheels = async () => {
    setError(null);
    setVehicle(null);
    setRecommendedTireSize(null);
    setWheelResults([]);

    const y = String(year || "").trim();
    const mk = String(make || "").trim();
    const md = String(model || "").trim();

    if (!y || !mk || !md) {
      setError("Please select Year, Make, and Model.");
      return;
    }

    try {
      setLoadingVehicle(true);
      const r1 = await fetch(
        `${API}/vehicles/search?year=${encodeURIComponent(y)}&make=${encodeURIComponent(mk)}&model=${encodeURIComponent(md)}`
      );
      const d1 = await r1.json();
      if (!r1.ok) throw new Error(d1?.error || "vehicle_search_failed");

      const v = d1?.vehicle || null;
      if (!v?.id) throw new Error("vehicle_id_missing");
      setVehicle(v);
      setLoadingVehicle(false);

      setLoadingPackages(true);
      const r2 = await fetch(
        `${API}/packages/plus-size?vehicleId=${encodeURIComponent(v.id)}&targetDiameter=20&wheelPageSize=20`
      );
      const d2 = await r2.json();
      if (!r2.ok) throw new Error(d2?.error || "package_engine_failed");

      const recSize = d2?.recommendedTireSizes?.[0]?.size || null;
      setRecommendedTireSize(recSize);
      setWheelResults(d2?.wheels?.results || []);
    } catch (e) {
      setError(String(e?.message || e));
    } finally {
      setLoadingVehicle(false);
      setLoadingPackages(false);
    }
  };

  return (
    <div className="page">
      <h1 className="title">Warehouse Tire Direct Sandbox</h1>

      <h3>Select Vehicle</h3>

      <div className="selectorRow">
        <select value={year || "Year"} onChange={(e) => loadMakes(e.target.value)}>
          <option>Year</option>
          {years.map((y) => (
            <option key={y} value={y}>
              {y}
            </option>
          ))}
        </select>

        <select value={make || "Make"} onChange={(e) => loadModels(e.target.value)} disabled={!year || year === "Year"}>
          <option>Make</option>
          {makes.map((m) => (
            <option key={m} value={m}>
              {m}
            </option>
          ))}
        </select>

        <select
          value={model || "Model"}
          onChange={(e) => {
            setModel(e.target.value);
            setVehicle(null);
            setRecommendedTireSize(null);
            setWheelResults([]);
            setError(null);
          }}
          disabled={!make || make === "Make"}
        >
          <option>Model</option>
          {models.map((m) => (
            <option key={m} value={m}>
              {m}
            </option>
          ))}
        </select>

        <button className="primaryBtn" onClick={onFindWheels} disabled={isLoading || !year || !make || !model}>
          {isLoading ? "Loading..." : "Find Wheels"}
        </button>
      </div>

      <div className="selectedRow">
        <strong>Selected:</strong> {selectedLabel || "(none)"}
      </div>

      {error ? <div className="errorBox">Error: {error}</div> : null}

      {/* Results */}
      {vehicle ? (
        <div className="resultsHeader">
          <div>
            <strong>Vehicle:</strong> {vehicle.year} {vehicle.make} {vehicle.model}
          </div>
          <div>
            <strong>Recommended Tire Size:</strong> {recommendedTireSize || "(none)"}
          </div>
        </div>
      ) : null}

      {wheelResults.length ? (
        <div className="grid">
          {wheelResults.map((w) => (
            <div key={w.sku} className="card">
              <div className="imgWrap">
                {w.primaryImage ? <img src={w.primaryImage} alt={w.title || w.sku} /> : <div className="imgPlaceholder">No image</div>}
              </div>

              <div className="cardBody">
                <div className="cardTitle">{w.brand ? `${w.brand} ` : ""}{w.title || w.sku}</div>

                <div className="meta">
                  <div>
                    <span className="label">Diameter:</span> {w.diameter ?? "—"}
                  </div>
                  <div>
                    <span className="label">Width:</span> {w.width ?? "—"}
                  </div>
                  <div>
                    <span className="label">Offset:</span> {w.offset != null ? `+${w.offset}` : "—"}
                  </div>
                  <div>
                    <span className="label">Finish:</span> {w.finish || "—"}
                  </div>
                </div>

                <div className="meta">
                  <div>
                    <span className="label">MSRP:</span> {w.msrp?.amount != null ? `${w.msrp.currency || "USD"} $${w.msrp.amount}` : "—"}
                  </div>
                  <div>
                    <span className="label">Stock:</span> global {w.stock?.global ?? "—"} / local {w.stock?.local ?? "—"}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : null}

      {!isLoading && vehicle && !wheelResults.length ? <div className="empty">No wheels returned for this vehicle/diameter.</div> : null}
    </div>
  );
}

export default App;

