const axios = require('axios');

/**
 * Wheel-Size API client (v2).
 *
 * Swagger: https://api.wheel-size.com/v2/swagger/
 * Auth: API key as query parameter `user_key`.
 * Base URL should look like: https://api.wheel-size.com/v2
 */
class WheelSizeClient {
  /**
   * @param {{baseUrl:string, apiKey:string, timeoutMs?:number}} opts
   */
  constructor({ baseUrl, apiKey, timeoutMs = 25_000 }) {
    this.baseUrl = baseUrl;
    this.apiKey = apiKey;

    this.http = axios.create({
      baseURL: baseUrl,
      timeout: timeoutMs,
      headers: { Accept: 'application/json' }
    });
  }

  _authParams(params = {}) {
    if (!this.apiKey) throw new Error('WheelSizeClient missing apiKey');
    return { user_key: this.apiKey, ...params };
  }

  async years() {
    const res = await this.http.get('/years/', {
      params: this._authParams({})
    });
    return res.data;
  }

  async makes({ year, region, ordering, lang, brands, brandsExclude } = {}) {
    const res = await this.http.get('/makes/', {
      params: this._authParams({
        year,
        region,
        ordering,
        lang,
        brands,
        brands_exclude: brandsExclude
      })
    });
    return res.data;
  }

  async models({ make, year, region, ordering, lang } = {}) {
    if (!make) throw new Error('WheelSizeClient.models requires make');
    const res = await this.http.get('/models/', {
      params: this._authParams({ make, year, region, ordering, lang })
    });
    return res.data;
  }

  async modifications({ make, model, year, generation, region, fuel, horsepower, horsepowerMin, horsepowerMax, trim, trimLevel, ordering, lang } = {}) {
    if (!make || !model) throw new Error('WheelSizeClient.modifications requires make and model');
    const res = await this.http.get('/modifications/', {
      params: this._authParams({
        make,
        model,
        year,
        generation,
        region,
        fuel,
        horsepower,
        horsepower_min: horsepowerMin,
        horsepower_max: horsepowerMax,
        trim,
        trim_level: trimLevel,
        ordering,
        lang
      })
    });
    return res.data;
  }

  async searchByModel({ make, model, year, generation, modification, region, addConfigurator, ordering, lang } = {}) {
    if (!make || !model) throw new Error('WheelSizeClient.searchByModel requires make and model');
    const res = await this.http.get('/search/by_model/', {
      params: this._authParams({
        make,
        model,
        year,
        generation,
        modification,
        region,
        add_configurator: addConfigurator,
        ordering,
        lang
      })
    });
    return res.data;
  }
}

module.exports = { WheelSizeClient };

const { randomUUID } = require('crypto');

class FitmentService {
  /**
   * @param {{db: import('pg').Pool, provider: any, cacheTtlDays?:number}} deps
   */
  constructor({ db, provider, cacheTtlDays = 7 }) {
    this.db = db;
    this.provider = provider;
    this.cacheTtlDays = cacheTtlDays;
  }

  /**
   * Get fitment for a vehicle. Uses cache if present, otherwise calls provider.
   * Returns normalized output contract.
   */
  async getFitmentForVehicle(vehicle) {
    // Ensure vehicle row exists (service may be called with an in-memory vehicle object)
    await this._upsertVehicle(vehicle);

    // 1) check cache (with TTL)
    const cached = await this._getCachedFitment(vehicle.id);
    if (cached && isFresh(cached?.source?.asOf, this.cacheTtlDays)) return cached;

    // 2) resolve via provider
    const fitment = await this.provider.getFitment({
      year: vehicle.year,
      make: vehicle.make,
      model: vehicle.model,
      submodel: vehicle.submodel,
      trim: vehicle.trim
    });

    // 3) persist normalized fitment + source
    await this._upsertFitment(vehicle.id, fitment, {
      provider: this.provider.getCapabilities().code,
      sourceRecordTimestamp: fitment?.sourceRecordTimestamp || null,
      confidence: fitment?.confidence ?? null,
      quality: fitment?.quality || null
    });

    return await this._getCachedFitment(vehicle.id);
  }

  /**
   * Creates/updates vehicle row.
   * Requires `vehicle.id` to be present.
   *
   * NOTE: This means a fitment lookup is not read-only; it may upsert vehicle records.
   * TODO: consider a uniqueness constraint + resolver for (year, make, model, submodel, trim)
   * to prevent duplicate vehicle identities if multiple UUIDs represent the same Y/M/M.
   */
  async _upsertVehicle(vehicle) {
    if (!vehicle?.id) throw new Error('FitmentService requires vehicle.id');
    await this.db.query({
      text: `
        insert into vehicle (id, year, make, model, submodel, trim)
        values ($1::uuid, $2, $3, $4, $5, $6)
        on conflict (id) do update set
          year = excluded.year,
          make = excluded.make,
          model = excluded.model,
          submodel = excluded.submodel,
          trim = excluded.trim
      `,
      values: [
        vehicle.id,
        vehicle.year,
        vehicle.make,
        vehicle.model,
        vehicle.submodel || null,
        vehicle.trim || null
      ]
    });
  }

  async _getCachedFitment(vehicleId) {
    const q = {
      text: `
        select vf.id as vehicle_fitment_id, vf.vehicle_id, vf.bolt_pattern, vf.center_bore_mm,
               vf.min_offset_mm, vf.max_offset_mm, vf.min_wheel_dia_in, vf.max_wheel_dia_in,
               vf.min_wheel_w_in, vf.max_wheel_w_in,
               vfs.provider, vfs.as_of as source_as_of, vfs.source_record_timestamp, vfs.confidence as source_confidence, vfs.quality
        from vehicle_fitment vf
        left join vehicle_fitment_source vfs on vfs.vehicle_fitment_id = vf.id
        where vf.vehicle_id = $1::uuid
        limit 1
      `,
      values: [vehicleId]
    };
    const { rows } = await this.db.query(q);
    if (!rows[0]) return null;

    const row = rows[0];

    // OEM tire sizes
    const { rows: oemRows } = await this.db.query({
      text: `select size from vehicle_oem_tire_size where vehicle_id = $1::uuid order by size asc`,
      values: [vehicleId]
    });

    let notes = {};
    try {
      notes = row.notes ? JSON.parse(row.notes) : {};
    } catch {
      notes = {};
    }

    return {
      vehicleId: row.vehicle_id,
      fitment: {
        boltPattern: row.bolt_pattern,
        centerBoreMm: row.center_bore_mm != null ? Number(row.center_bore_mm) : null,
        wheelDiameterRangeIn: [
          row.min_wheel_dia_in != null ? Number(row.min_wheel_dia_in) : null,
          row.max_wheel_dia_in != null ? Number(row.max_wheel_dia_in) : null
        ],
        wheelWidthRangeIn: [
          row.min_wheel_w_in != null ? Number(row.min_wheel_w_in) : null,
          row.max_wheel_w_in != null ? Number(row.max_wheel_w_in) : null
        ],
        offsetRangeMm: [
          row.min_offset_mm != null ? Number(row.min_offset_mm) : null,
          row.max_offset_mm != null ? Number(row.max_offset_mm) : null
        ],
        wheelSizes: Array.isArray(notes.wheelSizes) ? notes.wheelSizes : [],
        oemTireSizes: oemRows.map(r => r.size)
      },
      source: {
        provider: row.provider || null,
        asOf: row.source_as_of || null,
        sourceRecordTimestamp: row.source_record_timestamp || null,
        confidence: row.source_confidence != null ? Number(row.source_confidence) : null,
        quality: row.quality || null
      }
    };
  }

  async _upsertFitment(vehicleId, fitment, source) {
    // NOTE: this assumes the provider returns normalized fields. If not, normalize here.
    // This is still safe: package engine only sees what we persist.

    // Upsert vehicle_fitment (unique vehicle_id)
    const fitmentId = randomUUID();
    await this.db.query({
      text: `
        insert into vehicle_fitment (
          id, vehicle_id, bolt_pattern, center_bore_mm,
          min_offset_mm, max_offset_mm,
          min_wheel_dia_in, max_wheel_dia_in,
          min_wheel_w_in, max_wheel_w_in,
          notes
        ) values (
          $1::uuid, $2::uuid, $3, $4,
          $5, $6,
          $7, $8,
          $9, $10,
          $11
        )
        on conflict (vehicle_id) do update set
          bolt_pattern = excluded.bolt_pattern,
          center_bore_mm = excluded.center_bore_mm,
          min_offset_mm = excluded.min_offset_mm,
          max_offset_mm = excluded.max_offset_mm,
          min_wheel_dia_in = excluded.min_wheel_dia_in,
          max_wheel_dia_in = excluded.max_wheel_dia_in,
          min_wheel_w_in = excluded.min_wheel_w_in,
          max_wheel_w_in = excluded.max_wheel_w_in
        returning id
      `,
      values: [
        fitmentId,
        vehicleId,
        fitment.boltPattern || null,
        fitment.centerBoreMm ?? null,
        fitment.offsetRangeMm?.[0] ?? null,
        fitment.offsetRangeMm?.[1] ?? null,
        fitment.wheelDiameterRangeIn?.[0] ?? null,
        fitment.wheelDiameterRangeIn?.[1] ?? null,
        fitment.wheelWidthRangeIn?.[0] ?? null,
        fitment.wheelWidthRangeIn?.[1] ?? null,
        // Store JSON for richer cached response (wheelSizes, etc.)
        JSON.stringify({
          wheelSizes: fitment.wheelSizes || [],
          oemTireSizes: fitment.oemTireSizes || []
        })
      ]
    });

    // Find vehicle_fitment id for source insert
    const { rows } = await this.db.query({
      text: `select id from vehicle_fitment where vehicle_id = $1::uuid`,
      values: [vehicleId]
    });
    const vfId = rows[0]?.id;
    if (!vfId) return;

    await this.db.query({
      text: `
        insert into vehicle_fitment_source (
          id, vehicle_fitment_id, provider, source_record_timestamp, as_of, confidence, quality
        ) values (
          $1::uuid, $2::uuid, $3, $4, now(), $5, $6
        )
        on conflict (vehicle_fitment_id, provider) do update set
          source_record_timestamp = excluded.source_record_timestamp,
          as_of = excluded.as_of,
          confidence = excluded.confidence,
          quality = excluded.quality
      `,
      values: [randomUUID(), vfId, source.provider, source.sourceRecordTimestamp, source.confidence, source.quality]
    });

    // OEM tire sizes (refresh list)
    const sizes = Array.from(new Set((fitment?.oemTireSizes || [])
      .map(normalizeOemTireSize)
      .filter(Boolean)));
    if (sizes.length) {
      await this.db.query({
        text: `delete from vehicle_oem_tire_size where vehicle_id = $1::uuid`,
        values: [vehicleId]
      });
      for (const s of sizes) {
        await this.db.query({
          text: `insert into vehicle_oem_tire_size (id, vehicle_id, size, position) values ($1::uuid, $2::uuid, $3, $4)`,
          values: [randomUUID(), vehicleId, s, 'all']
        });
      }
    }
  }
}

function normalizeOemTireSize(v) {
  if (!v) return null;
  const s = String(v).trim().toUpperCase();
  const m = s.match(/(\d{3}\/\d{2,3}R\d{2}(?:\.\d)?)/i);
  return (m ? m[1] : s) || null;
}

function isFresh(asOf, ttlDays) {
  if (!asOf) return false;
  const t = new Date(asOf).getTime();
  if (!Number.isFinite(t)) return false;
  const ageMs = Date.now() - t;
  return ageMs >= 0 && ageMs <= (ttlDays * 24 * 60 * 60 * 1000);
}

module.exports = { FitmentService };

const { WheelSizeClient } = require('./wheelSizeClient');

/**
 * Fitment provider adapter for Wheel-Size API.
 *
 * API docs: https://api.wheel-size.com/v2/swagger/
 * Auth: `user_key` query param.
 */
class WheelSizeFitmentAdapter {
  /**
   * @param {{baseUrl:string, apiKey:string, defaultRegion?:string}} opts
   */
  constructor({ baseUrl, apiKey, defaultRegion = 'usdm' }) {
    this.code = 'WHEEL_SIZE_API';
    this.baseUrl = baseUrl;
    this.apiKey = apiKey;
    this.defaultRegion = defaultRegion;

    this.client = new WheelSizeClient({ baseUrl, apiKey });
  }

  getCapabilities() {
    return { code: this.code, mode: 'api', supportsVinLookup: false };
  }

  /**
   * Returns normalized fitment contract:
   * - boltPattern
   * - centerBoreMm
   * - wheelDiameterRangeIn
   * - wheelWidthRangeIn
   * - offsetRangeMm
   * - oemTireSizes
   *
   * @param {{year:number, make:string, model:string, submodel?:string, trim?:string}} vehicle
   */
  async getFitment(vehicle) {
    if (!this.baseUrl) throw new Error('WheelSize fitment provider not configured (WHEEL_SIZE_BASE_URL)');
    if (!this.apiKey) throw new Error('WheelSize fitment provider not configured (WHEEL_SIZE_API_KEY)');

    const year = Number(vehicle.year);
    if (!Number.isFinite(year)) throw new Error('WheelSizeFitmentAdapter.getFitment requires vehicle.year');

    const makeSlug = await this._resolveMakeSlug(vehicle.make, year);
    const modelSlug = await this._resolveModelSlug(makeSlug, vehicle.model, year);

    // If trim provided, try to resolve a modification slug for better accuracy.
    const modificationSlug = vehicle.trim
      ? await this._resolveModificationSlug({ makeSlug, modelSlug, year, trim: vehicle.trim })
      : null;

    // Swagger requires make+model + (year|generation) + (modification|region)
    const payload = await this.client.searchByModel({
      make: makeSlug,
      model: modelSlug,
      year,
      modification: modificationSlug || undefined,
      region: modificationSlug ? undefined : this.defaultRegion
    });

    const rows = payload?.data || [];
    if (!Array.isArray(rows) || rows.length === 0) {
      return {
        boltPattern: null,
        centerBoreMm: null,
        wheelDiameterRangeIn: [null, null],
        wheelWidthRangeIn: [null, null],
        offsetRangeMm: [null, null],
        oemTireSizes: [],
        confidence: 0.2,
        quality: 'no_results'
      };
    }

    return normalizeFitmentFromSearchByModel(rows);
  }

  async _resolveMakeSlug(makeName, year) {
    const guess = slugify(makeName);

    // Quick path: if guess works for models(), keep it.
    try {
      await this.client.models({ make: guess, year });
      return guess;
    } catch {
      // continue
    }

    // Slow path: list makes and match.
    const makesPayload = await this.client.makes({ year });
    const makes = makesPayload?.data || [];
    const found = makes.find((m) =>
      eqName(m?.name, makeName) ||
      eqName(m?.name_en, makeName) ||
      eqSlug(m?.slug, guess)
    );

    if (!found?.slug) throw new Error(`WheelSize: unable to resolve make slug for '${makeName}'`);
    return found.slug;
  }

  async _resolveModelSlug(makeSlug, modelName, year) {
    const guess = slugify(modelName);

    try {
      const payload = await this.client.models({ make: makeSlug, year });
      const models = payload?.data || [];
      const found = models.find((m) =>
        eqName(m?.name, modelName) ||
        eqName(m?.name_en, modelName) ||
        eqSlug(m?.slug, guess)
      );
      if (found?.slug) return found.slug;
    } catch {
      // continue
    }

    // Best-effort fallback.
    return guess;
  }

  async _resolveModificationSlug({ makeSlug, modelSlug, year, trim }) {
    const payload = await this.client.modifications({
      make: makeSlug,
      model: modelSlug,
      year,
      trim
    });

    const mods = payload?.data || [];
    if (!Array.isArray(mods) || mods.length === 0) return null;

    // Prefer the best trim scoring if present.
    const best = mods
      .slice()
      .sort((a, b) => (Number(b?.trim_scoring) || 0) - (Number(a?.trim_scoring) || 0))[0];

    return best?.slug || null;
  }
}

function normalizeFitmentFromSearchByModel(rows) {
  const tech = rows.find((r) => r?.technical)?.technical || {};

  const boltPattern = tech.bolt_pattern || null;
  const centerBoreMm = parseMaybeNumber(tech.centre_bore) ?? parseMaybeNumber(tech.rear_axis_centre_bore) ?? null;

  const stockWheelPairs = rows
    .flatMap((r) => (Array.isArray(r?.wheels) ? r.wheels : []))
    .filter((wp) => wp?.is_stock);

  const diaVals = [];
  const widthVals = [];
  const offsetVals = [];
  const oemTires = [];

  for (const wp of stockWheelPairs) {
    for (const axle of ['front', 'rear']) {
      const a = wp?.[axle];
      if (!a) continue;

      if (a.rim_diameter != null) diaVals.push(Number(a.rim_diameter));
      if (a.rim_width != null) widthVals.push(Number(a.rim_width));
      if (a.rim_offset != null) offsetVals.push(Number(a.rim_offset));

      const t = String(a.tire_full || a.tire || '').trim();
      if (t) {
        const m = t.match(/(\d{3}\/\d{2,3}R\d{2}(?:\.\d)?)/i);
        oemTires.push((m ? m[1] : t).toUpperCase());
      }
    }
  }

  const wheelSizes = Array.from(
    new Set(
      stockWheelPairs
        .flatMap((wp) => ['front', 'rear'].map((axle) => wp?.[axle]).filter(Boolean))
        .map((a) => {
          const d = parseMaybeNumber(a?.rim_diameter);
          const w = parseMaybeNumber(a?.rim_width);
          const off = parseMaybeNumber(a?.rim_offset);
          if (d == null && w == null && off == null) return null;
          // stable key for de-dupe
          return JSON.stringify({ diameterIn: d, widthIn: w, offsetMm: off });
        })
        .filter(Boolean)
    )
  ).map((s) => JSON.parse(s));

  return {
    boltPattern,
    centerBoreMm,
    wheelDiameterRangeIn: range(diaVals),
    wheelWidthRangeIn: range(widthVals),
    offsetRangeMm: range(offsetVals),
    oemTireSizes: Array.from(new Set(oemTires)).sort(),
    wheelSizes,

    // Rough metadata for FitmentService provenance.
    confidence: stockWheelPairs.length ? 0.85 : 0.6,
    quality: stockWheelPairs.length ? 'ok' : 'no_stock_wheel_pairs'
  };
}

function range(nums) {
  const finite = nums.filter((n) => Number.isFinite(n));
  if (!finite.length) return [null, null];
  return [Math.min(...finite), Math.max(...finite)];
}

function parseMaybeNumber(v) {
  if (v == null) return null;
  const s = String(v).trim();
  if (!s || s.toUpperCase() === 'N/A') return null;
  const n = Number(s);
  return Number.isFinite(n) ? n : null;
}

function slugify(s) {
  return String(s || '')
    .trim()
    .toLowerCase()
    .replace(/&/g, 'and')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '');
}

function eqName(a, b) {
  if (!a || !b) return false;
  return String(a).trim().toLowerCase() === String(b).trim().toLowerCase();
}

function eqSlug(a, b) {
  return eqName(a, b);
}

module.exports = { WheelSizeFitmentAdapter };

class VehicleService {
  /**
   * @param {{db: import('pg').Pool}} deps
   */
  constructor({ db }) {
    this.db = db;
  }

  async listMakes({ year }) {
    const q = {
      text: `select distinct make from vehicle where ($1::int is null or year = $1) order by make asc`,
      values: [year ?? null]
    };
    const { rows } = await this.db.query(q);
    return rows.map(r => r.make);
  }

  async listModels({ year, make }) {
    const q = {
      text: `select distinct model from vehicle where ($1::int is null or year = $1) and ($2::text is null or make = $2) order by model asc`,
      values: [year ?? null, make ?? null]
    };
    const { rows } = await this.db.query(q);
    return rows.map(r => r.model);
  }

  async getVehicleById(vehicleId) {
    const { rows } = await this.db.query({
      text: `select id, year, make, model, submodel, trim from vehicle where id = $1::uuid`,
      values: [vehicleId]
    });
    return rows[0] || null;
  }

  /**
   * Find or create a vehicle identity for a year/make/model lookup.
   * Uses a best-effort match on (year, make, model) with null submodel/trim.
   */
  async getOrCreateVehicle({ year, make, model }) {
    const { rows } = await this.db.query({
      text: `
        select id, year, make, model, submodel, trim
        from vehicle
        where year = $1
          and lower(make) = lower($2)
          and lower(model) = lower($3)
          and submodel is null
          and trim is null
        order by created_at asc
        limit 1
      `,
      values: [year, make, model]
    });

    if (rows[0]) return rows[0];

    const id = require('crypto').randomUUID();
    await this.db.query({
      text: `insert into vehicle (id, year, make, model, submodel, trim) values ($1::uuid, $2, $3, $4, null, null)`,
      values: [id, year, make, model]
    });

    return { id, year, make, model, submodel: null, trim: null };
  }
}

module.exports = { VehicleService };

