  const [models, setModels] = useState([]);

  const [year, setYear] = useState("");
  const [make, setMake] = useState("");
  const [model, setModel] = useState("");

  // Trims/modifications
  const [trims, setTrims] = useState([]); // [{trim, modification, ...}]
  const [selectedModification, setSelectedModification] = useState("");
  const [selectedTrimLabel, setSelectedTrimLabel] = useState("");

  // Fitment-based selectors
  const [selectedTireSize, setSelectedTireSize] = useState("");

  // Wheels/packages UI controls
  const [diameterFilter, setDiameterFilter] = useState("all"); // all | number-as-string
  const [wheelSort, setWheelSort] = useState("featured"); // featured | price_asc | price_desc | brand_asc

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);

  // Shared: response from /v1/vehicles/search (includes fitment)
  const [vehicleSearch, setVehicleSearch] = useState(null);

  // Results per tab
  const [tireResults, setTireResults] = useState([]);
  const [wheelResults, setWheelResults] = useState([]);
  const [recommendedTireSize, setRecommendedTireSize] = useState(null);

  const API = "http://127.0.0.1:8790/v1";

  const selectedLabel = useMemo(() => {
    const parts = [year, make, model].filter(Boolean);
    return parts.join(" ");
  }, [year, make, model]);

  const vehicleLabel = useMemo(() => {
    const v = vehicleSearch?.vehicle;
    if (!v) return null;
    return `${v.year} ${v.make} ${v.model}`;
  }, [vehicleSearch]);

  const fitmentLabel = useMemo(() => {
    if (!vehicleSearch) return null;
    const bp = vehicleSearch?.boltPattern || "—";
    const cb = vehicleSearch?.centerBoreMm ?? "—";
    const dia = vehicleSearch?.wheelDiameterRangeIn || [null, null];
    const wid = vehicleSearch?.wheelWidthRangeIn || [null, null];
    const off = vehicleSearch?.offsetRangeMm || [null, null];

    const fmtRange = (r) => {
      if (!Array.isArray(r)) return "—";
      const a = r[0];
      const b = r[1];
      if (a == null && b == null) return "—";
      if (a != null && b != null && a === b) return String(a);
      return `${a ?? "—"} - ${b ?? "—"}`;
    };

    return `BP ${bp} / CB ${cb} / Dia ${fmtRange(dia)} / W ${fmtRange(wid)} / Off ${fmtRange(off)}`;
  }, [vehicleSearch]);

  const resetAllResults = () => {
    setVehicleSearch(null);
    setTireResults([]);
    setWheelResults([]);
    setRecommendedTireSize(null);
  };

  const resetTrimAndFitment = () => {
    setTrims([]);
    setSelectedModification("");
    setSelectedTrimLabel("");
    setSelectedTireSize("");
    setDiameterFilter("all");
    setWheelSort("featured");
    resetAllResults();
  };

  useEffect(() => {
    (async () => {
      try {
        setError(null);
        const r = await fetch(`${API}/vehicles/years`);
        const d = await r.json();
        if (!r.ok) throw new Error(d?.error || "failed_to_load_years");
        setYears(d.results || []);
      } catch (e) {
        setError(String(e?.message || e));
      }
    })();
  }, []);

  const loadMakes = async (y) => {
    const yy = String(y || "").trim();
    setYear(yy);
    setMake("");
    setModel("");
    setMakes([]);
    setModels([]);

    resetTrimAndFitment();
    setError(null);

    if (!yy || yy === "Year") return;

    try {
      const r = await fetch(`${API}/vehicles/makes?year=${encodeURIComponent(yy)}`);
      const d = await r.json();
      if (!r.ok) throw new Error(d?.error || "failed_to_load_makes");
      setMakes(d.results || []);
    } catch (e) {
      setError(String(e?.message || e));
    }
  };

  const loadModels = async (m) => {
    const mm = String(m || "").trim();
    setMake(mm);
    setModel("");
    setModels([]);

    resetTrimAndFitment();
    setError(null);

    if (!mm || mm === "Make") return;

    try {
      const r = await fetch(`${API}/vehicles/models?year=${encodeURIComponent(year)}&make=${encodeURIComponent(mm)}`);
      const d = await r.json();
      if (!r.ok) throw new Error(d?.error || "failed_to_load_models");
      setModels(d.results || []);
    } catch (e) {
      setError(String(e?.message || e));
    }
  };

  const loadTrims = async ({ y, mk, md }) => {
    const r = await fetch(
      `${API}/vehicles/trims?year=${encodeURIComponent(y)}&make=${encodeURIComponent(mk)}&model=${encodeURIComponent(md)}`
    );
    const d = await r.json();
    if (!r.ok) throw new Error(d?.error || "failed_to_load_trims");
    return d?.results || [];
  };

  const loadFitmentForTrim = async ({ y, mk, md, modification, trim }) => {
    const qs = new URLSearchParams();
    qs.set("year", y);
    qs.set("make", mk);
    qs.set("model", md);
    if (modification) qs.set("modification", modification);
    if (trim) qs.set("trim", trim);

    const r = await fetch(`${API}/vehicles/search?${qs.toString()}`);
    const d = await r.json();
    if (!r.ok) throw new Error(d?.error || "vehicle_search_failed");
    if (!d?.vehicle?.id) throw new Error("vehicle_id_missing");
    return d;
  };

  const onModelSelected = async (md) => {
    const modelVal = String(md || "").trim();
    setModel(modelVal);

    resetTrimAndFitment();
    setError(null);

    if (!modelVal || modelVal === "Model") return;

    try {
      setIsLoading(true);
      const y = String(year || "").trim();
      const mk = String(make || "").trim();

      const ts = await loadTrims({ y, mk, md: modelVal });
      setTrims(ts);

      // If Wheel-Size returns no modifications, we can still allow searches without trim.
      if (!ts.length) {
        const vs = await loadFitmentForTrim({ y, mk, md: modelVal, modification: null, trim: null });
        setVehicleSearch(vs);
        const tire0 = Array.isArray(vs?.tireSizes) ? vs.tireSizes[0] : "";
        if (tire0) setSelectedTireSize(tire0);

        // Default: show all diameters first.
        setDiameterFilter("all");
      }
    } catch (e) {
      setError(String(e?.message || e));
    } finally {
      setIsLoading(false);
    }
  };

  const onTrimSelected = async (modification) => {
    const mod = String(modification || "").trim();
    setSelectedModification(mod);

    resetAllResults();
    setError(null);

    if (!mod || mod === "Trim") {
      setSelectedTrimLabel("");
      setVehicleSearch(null);
      return;
    }

    const t = trims.find((x) => x.modification === mod);
    const trim = t?.trim || "";
    setSelectedTrimLabel(trim);

    try {
      setIsLoading(true);
      const y = String(year || "").trim();
      const mk = String(make || "").trim();
      const md = String(model || "").trim();

      const vs = await loadFitmentForTrim({ y, mk, md, modification: mod, trim });
      setVehicleSearch(vs);

      const tire0 = Array.isArray(vs?.tireSizes) ? vs.tireSizes[0] : "";
      setSelectedTireSize(tire0 || "");

      // Default for wheels: show all diameters (upsizing enabled).
      setDiameterFilter("all");
    } catch (e) {
      setError(String(e?.message || e));
    } finally {
      setIsLoading(false);
    }
  };

  const ensureVehicleSearchLoaded = async () => {
    if (trims.length && !selectedModification) throw new Error("Please select a Trim.");

    if (vehicleSearch?.vehicle?.id) return vehicleSearch;

    const y = String(year || "").trim();
    const mk = String(make || "").trim();
    const md = String(model || "").trim();
    if (!y || !mk || !md) throw new Error("Please select Year, Make, and Model.");

    const vs = await loadFitmentForTrim({
      y,
      mk,
      md,
      modification: selectedModification || null,
      trim: selectedTrimLabel || null
    });

    setVehicleSearch(vs);
    return vs;
  };

  const tireSizeOptions = useMemo(() => {
    const vs = vehicleSearch;
    return Array.isArray(vs?.tireSizes) ? vs.tireSizes : [];
  }, [vehicleSearch]);

  const wheelDiameterOptions = useMemo(() => {
    const vs = vehicleSearch;
    if (!vs) return [];

    // Use fitment range when present; fall back to wheelSizes array.
    const fromWheelSizes = uniqueSorted((vs.wheelSizes || []).map((w) => w?.diameterIn));
    const fromRange = Array.isArray(vs.wheelDiameterRangeIn)
      ? uniqueSorted([vs.wheelDiameterRangeIn[0], vs.wheelDiameterRangeIn[1]])
      : [];

    const merged = uniqueSorted([...fromWheelSizes, ...fromRange]).filter((n) => n != null);
    return merged;
  }, [vehicleSearch]);

  const selectedDiameterNumber = useMemo(() => {
    if (diameterFilter === "all") return null;
    const n = Number(diameterFilter);
    return Number.isFinite(n) ? n : null;
  }, [diameterFilter]);

  const onSearchTires = async () => {
    setError(null);
    resetAllResults();

    try {
      setIsLoading(true);

      const vs = await ensureVehicleSearchLoaded();

      const size = selectedTireSize || (Array.isArray(vs?.tireSizes) ? vs.tireSizes[0] : null);
      if (!size) throw new Error("oem_tire_size_missing");

      const r2 = await fetch(`${API}/tires/search?size=${encodeURIComponent(size)}&pageSize=24`);
      const d2 = await r2.json();
      if (!r2.ok) throw new Error(d2?.error || "tire_search_failed");

      setVehicleSearch(vs);
      setTireResults(d2?.results || []);
    } catch (e) {
      setError(String(e?.message || e));
    } finally {
      setIsLoading(false);
    }
  };

  const onSearchWheels = async () => {
    setError(null);
    resetAllResults();

    try {
      setIsLoading(true);

      const vs = await ensureVehicleSearchLoaded();
      const boltPattern = vs?.boltPattern || null;
      if (!boltPattern) throw new Error("bolt_pattern_missing");

      const qs = new URLSearchParams();
      qs.set("pageSize", "60");
      qs.set("boltPattern", boltPattern);
      if (selectedDiameterNumber != null) qs.set("diameter", String(selectedDiameterNumber));

      const r2 = await fetch(`${API}/wheels/search?${qs.toString()}`);
      const d2 = await r2.json();
      if (!r2.ok) throw new Error(d2?.error || "wheel_search_failed");

      setVehicleSearch(vs);
      setWheelResults(d2?.results || []);
    } catch (e) {
      setError(String(e?.message || e));
    } finally {
      setIsLoading(false);
    }
  };

  const onSearchPackages = async () => {
    setError(null);
    resetAllResults();

    try {
      setIsLoading(true);

      const vs = await ensureVehicleSearchLoaded();

      const vehicleId = vs.vehicle.id;
      const vehicleModificationId = vs.vehicleModificationId || "";

      // Packages need a target diameter; default to selected or max fitment diameter.
      const targetDia = selectedDiameterNumber
        ?? (Array.isArray(vs.wheelDiameterRangeIn) ? Number(vs.wheelDiameterRangeIn[1]) : null)
        ?? 20;

      const qs = new URLSearchParams();
      qs.set("vehicleId", vehicleId);
      if (vehicleModificationId) qs.set("vehicleModificationId", vehicleModificationId);
      qs.set("targetDiameter", String(targetDia));
      qs.set("wheelPageSize", "20");

      const r2 = await fetch(`${API}/packages/plus-size?${qs.toString()}`);
      const d2 = await r2.json();
      if (!r2.ok) throw new Error(d2?.error || "package_engine_failed");

      setVehicleSearch(vs);
      setRecommendedTireSize(d2?.recommendedTireSizes?.[0]?.size || null);
      setWheelResults(d2?.wheels?.results || []);
    } catch (e) {
      setError(String(e?.message || e));
    } finally {
      setIsLoading(false);
    }
  };

  const onSearch = () => {
    if (tab === "tires") return onSearchTires();
    if (tab === "wheels") return onSearchWheels();
    return onSearchPackages();
  };

  const actionLabel = tab === "tires" ? "Find Tires" : tab === "wheels" ? "Find Wheels" : "Find Packages";

  const setTabSafe = (t) => {
    setTab(t);
    resetAllResults();
    setError(null);
  };

  const wheelResultsView = useMemo(() => {
    const rows = [...(wheelResults || [])];

    // Client-side sort (keeps backend untouched)
    const getPrice = (w) => {
      const amt = w?.msrp?.amount;
      const n = amt != null ? Number(amt) : null;
      return Number.isFinite(n) ? n : null;
    };

    if (wheelSort === "price_asc") {
      rows.sort((a, b) => (getPrice(a) ?? Number.POSITIVE_INFINITY) - (getPrice(b) ?? Number.POSITIVE_INFINITY));
    } else if (wheelSort === "price_desc") {
      rows.sort((a, b) => (getPrice(b) ?? -1) - (getPrice(a) ?? -1));
    } else if (wheelSort === "brand_asc") {
      rows.sort((a, b) => String(a?.brand || "").localeCompare(String(b?.brand || "")) || String(a?.title || "").localeCompare(String(b?.title || "")));
    }

    return rows;
  }, [wheelResults, wheelSort]);

  const canSearch = !!year && !!make && !!model && (!trims.length || !!selectedModification || !trims.length) && !isLoading;

  const showWheelControls = tab === "wheels" || tab === "packages";

  return (
    <div className="page">
      <h1 className="title">Warehouse Tire Direct Sandbox</h1>

      <div className="tabs">
        <button className={tab === "tires" ? "tab active" : "tab"} onClick={() => setTabSafe("tires")}>
          Tires
        </button>
        <button className={tab === "wheels" ? "tab active" : "tab"} onClick={() => setTabSafe("wheels")}>
          Wheels
        </button>
        <button className={tab === "packages" ? "tab active" : "tab"} onClick={() => setTabSafe("packages")}>
          Packages
        </button>
      </div>

      <h3>Select Vehicle</h3>

      <div className="selectorRow">
        <select value={year || "Year"} onChange={(e) => loadMakes(e.target.value)}>
          <option>Year</option>
          {years.map((y) => (
            <option key={y} value={y}>
              {y}
            </option>
          ))}
        </select>

        <select value={make || "Make"} onChange={(e) => loadModels(e.target.value)} disabled={!year || year === "Year"}>
          <option>Make</option>
          {makes.map((m) => (
            <option key={m} value={m}>
              {m}
            </option>
          ))}
        </select>

        <select value={model || "Model"} onChange={(e) => onModelSelected(e.target.value)} disabled={!make || make === "Make"}>
          <option>Model</option>
          {models.map((m) => (
            <option key={m} value={m}>
              {m}
            </option>
          ))}
        </select>

        {/* Trim (Wheel-Size modification) */}
        <select
          value={selectedModification || "Trim"}
          onChange={(e) => onTrimSelected(e.target.value)}
          disabled={!model || model === "Model" || isLoading || (!trims.length && !vehicleSearch)}
        >
          <option>Trim</option>
          {trims.map((t) => (
            <option key={t.modification} value={t.modification}>
              {t.trim}
            </option>
          ))}
        </select>

        {/* Tires: tire size picker */}
        {tab === "tires" && tireSizeOptions.length ? (
          <select value={selectedTireSize || "Tire Size"} onChange={(e) => setSelectedTireSize(e.target.value)} disabled={isLoading}>
            <option value="">Tire Size</option>
            {tireSizeOptions.map((s) => (
              <option key={s} value={s}>
                {s}
              </option>
            ))}
          </select>
        ) : null}

        <button className="primaryBtn" onClick={onSearch} disabled={!canSearch}>
          {isLoading ? "Loading..." : actionLabel}
        </button>
      </div>

      {/* Wheel controls row (diameter + sort) */}
      {showWheelControls && vehicleSearch ? (
        <div className="controlsRow">
          <div className="chipGroup">
            <span className="controlLabel">Diameter:</span>
            <button
              className={diameterFilter === "all" ? "chip active" : "chip"}
              onClick={() => {
                setDiameterFilter("all");
                resetAllResults();
              }}
              disabled={isLoading}
            >
              All
            </button>
            {wheelDiameterOptions.map((d) => {
              const key = String(d);
              return (
                <button
                  key={key}
                  className={diameterFilter === key ? "chip active" : "chip"}
                  onClick={() => {
                    setDiameterFilter(key);
                    resetAllResults();
                  }}
                  disabled={isLoading}
                >
                  {d}"
                </button>
              );
            })}
          </div>

          <div className="sortRow">
            <span className="controlLabel">Sort:</span>
            <select value={wheelSort} onChange={(e) => setWheelSort(e.target.value)} disabled={isLoading}>
              <option value="featured">Featured</option>
              <option value="price_asc">Price (Low → High)</option>
              <option value="price_desc">Price (High → Low)</option>
              <option value="brand_asc">Brand (A → Z)</option>
            </select>
          </div>
        </div>
      ) : null}

      <div className="selectedRow">
        <strong>Selected:</strong> {selectedLabel || "(none)"}
        {selectedTrimLabel ? <span className="muted"> — Trim: {selectedTrimLabel}</span> : null}
      </div>

      {error ? <div className="errorBox">Error: {error}</div> : null}

      {vehicleLabel ? (
        <div className="resultsHeader">
          <div>
            <strong>Vehicle:</strong> {vehicleLabel}
            {selectedTrimLabel ? ` (${selectedTrimLabel})` : ""}
          </div>
          <div>
            <strong>Fitment:</strong> {fitmentLabel || "—"}
          </div>
          {tab === "packages" ? (
            <div>
              <strong>Recommended Tire Size:</strong> {recommendedTireSize || "(none)"}
            </div>
          ) : null}
        </div>
      ) : null}

      {/* Tires grid */}
      {tab === "tires" && tireResults.length ? (
        <div className="grid">
          {tireResults.map((t) => {
            const p = t?.raw?.properties || {};
            const modelName = p.model || t?.title || null;
            const size = t?.size || p.size || null;

            const load = p.loadIndex ?? p.load_rating ?? p.loadIndex1 ?? null;
            const speed = p.speedRating ?? p.speed_rating ?? null;
            const season = p.season ?? null;

            const price = t?.msrp?.amount != null ? `$${Number(t.msrp.amount).toFixed(0)}` : "—";

            return (
              <div key={t.sku} className="card">
                <div className="cardBody">
                  <div className="cardTitle">
                    {t.brand ? `${t.brand} ` : ""}
                    {modelName || t.sku}
                  </div>

                  <div className="priceBig">{price}</div>

                  <div className="meta">
                    <div>
                      <span className="label">Size:</span> {size || "—"}
                    </div>
                    <div>
                      <span className="label">Season:</span> {season || "—"}
                    </div>
                    <div>
                      <span className="label">Load:</span> {load ?? "—"}
                    </div>
                    <div>
                      <span className="label">Speed:</span> {speed ?? "—"}
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      ) : null}

      {/* Wheels + Packages: wheel grid */}
      {(tab === "wheels" || tab === "packages") && wheelResultsView.length ? (
        <div className="grid">
          {wheelResultsView.map((w) => (
            <div key={w.sku} className="wheelCard">
              <div className="imgWrap">
                {w.primaryImage ? <img src={w.primaryImage} alt={w.title || w.sku} /> : <div className="imgPlaceholder">No image</div>}
              </div>

              <div className="wheelBody">
                <div className="wheelTop">
                  <div className="wheelName">
                    <div className="wheelBrand">{w.brand || ""}</div>
                    <div className="wheelTitle">{w.title || w.sku}</div>
                  </div>
                  <div className="priceBig">{money(w.msrp)}</div>
                </div>

                <div className="wheelSizeLine">{wheelSizeLine(w)}</div>

                <div className="meta">
                  <div>
                    <span className="label">Finish:</span> {w.finish || "—"}
                  </div>
                  <div>
                    <span className="label">MSRP:</span> {w.msrp?.amount != null ? `${w.msrp.currency || "USD"} ${money(w.msrp)}` : "—"}
                  </div>
                  {tab === "packages" ? (
                    <div>
                      <span className="label">Stock:</span> global {w.stock?.global ?? "—"} / local {w.stock?.local ?? "—"}
                    </div>
                  ) : null}
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : null}

      {!isLoading && vehicleLabel && tab === "tires" && !tireResults.length ? <div className="empty">No tires returned.</div> : null}
      {!isLoading && vehicleLabel && (tab === "wheels" || tab === "packages") && !wheelResultsView.length ? (
        <div className="empty">No wheels returned.</div>
      ) : null}
    </div>
  );
}

export default App;
"}

