function normalizeTireSize(s) {
  if (!s) return null;
  // Ignore ZR, strip load/speed suffixes.
  return String(s)
    .trim()
    .toUpperCase()
    .replace(/\s+/g, '')
    .replace('ZR', 'R')
    .replace(/(\d{3}\/\d{2,3}R\d{2}(?:\.\d)?).*/, '$1');
}

