const wheelResultsView = useMemo(() => {
  let rows = [...(wheelResults || [])];

  const getPrice = (w) => {
    const amt = w?.msrp?.amount;
    const n = amt != null ? Number(amt) : null;
    return Number.isFinite(n) ? n : null;
  };

  // Client-side price filtering (because backend may not support it)
  const minP = wheelFilters.minPrice ? Number(wheelFilters.minPrice) : null;
  const maxP = wheelFilters.maxPrice ? Number(wheelFilters.maxPrice) : null;
  if (Number.isFinite(minP)) rows = rows.filter((w) => (getPrice(w) ?? Number.POSITIVE_INFINITY) >= minP);
  if (Number.isFinite(maxP)) rows = rows.filter((w) => (getPrice(w) ?? -1) <= maxP);

  // Client-side sort
  if (wheelSort === "price_asc") {
    rows.sort((a, b) => (getPrice(a) ?? Number.POSITIVE_INFINITY) - (getPrice(b) ?? Number.POSITIVE_INFINITY));
  } else if (wheelSort === "price_desc") {
    rows.sort((a, b) => (getPrice(b) ?? -1) - (getPrice(a) ?? -1));
  } else if (wheelSort === "brand_asc") {
    rows.sort((a, b) => String(a?.brand || "").localeCompare(String(b?.brand || "")) || String(a?.title || "").localeCompare(String(b?.title || "")));
  }

  return rows;
}, [wheelResults, wheelSort, wheelFilters.minPrice, wheelFilters.maxPrice]);

const wheelVariantGroups = useMemo(() => groupWheelVariants(wheelResultsView), [wheelResultsView]);

