const wheelVariantGroups = useMemo(() => groupWheelVariants(wheelResultsView), [wheelResultsView]);

const tireResultsView = useMemo(() => {
  let rows = [...(tireResults || [])];

  const getBrand = (t) => String(t?.brand || '').toLowerCase();
  const getSeason = (t) => String(t?.raw?.properties?.season || '').toLowerCase();
  const getSpeed = (t) => String(t?.raw?.properties?.speedRating || t?.raw?.properties?.speed_rating || '').toLowerCase();
  const getRunFlat = (t) => {
    const rf = t?.raw?.properties?.runFlat;
    if (rf === true || rf === 1 || rf === '1' || rf === 'true') return true;
    if (rf === false || rf === 0 || rf === '0' || rf === 'false') return false;
    return null;
  };
  const getPrice = (t) => {
    const amt = t?.msrp?.amount;
    const n = amt != null ? Number(amt) : null;
    return Number.isFinite(n) ? n : null;
  };

  if (tireFilters.brand) {
    const q = tireFilters.brand.toLowerCase();
    rows = rows.filter((t) => getBrand(t).includes(q));
  }
  if (tireFilters.season) {
    const q = tireFilters.season.toLowerCase();
    rows = rows.filter((t) => getSeason(t).includes(q));
  }
  if (tireFilters.speedRating) {
    const q = tireFilters.speedRating.toLowerCase();
    rows = rows.filter((t) => getSpeed(t) === q);
  }
  if (tireFilters.runFlat === 'true') rows = rows.filter((t) => getRunFlat(t) === true);
  if (tireFilters.runFlat === 'false') rows = rows.filter((t) => getRunFlat(t) === false);

  const minP = tireFilters.minPrice ? Number(tireFilters.minPrice) : null;
  const maxP = tireFilters.maxPrice ? Number(tireFilters.maxPrice) : null;
  if (Number.isFinite(minP)) rows = rows.filter((t) => (getPrice(t) ?? Number.POSITIVE_INFINITY) >= minP);
  if (Number.isFinite(maxP)) rows = rows.filter((t) => (getPrice(t) ?? -1) <= maxP);

  return rows;
}, [tireResults, tireFilters]);

const packageBundlesView = useMemo(() => {
  let rows = [...(packageBundles || [])];

  const getWheelPrice = (b) => {
    const amt = b?.wheel?.msrp?.amount;
    const n = amt != null ? Number(amt) : null;
    return Number.isFinite(n) ? n : null;
  };
  const getTirePrice = (b) => {
    const amt = b?.tire?.msrp?.amount;
    const n = amt != null ? Number(amt) : null;
    return Number.isFinite(n) ? n : null;
  };
  const getTotal = (b) => (getWheelPrice(b) ?? 0) + (getTirePrice(b) ?? 0);

  if (packageFilters.wheelBrand) {
    const q = packageFilters.wheelBrand.toLowerCase();
    rows = rows.filter((b) => String(b?.wheel?.brand || '').toLowerCase().includes(q));
  }
  if (packageFilters.wheelFinish) {
    const q = packageFilters.wheelFinish.toLowerCase();
    rows = rows.filter((b) => String(b?.wheel?.finish || '').toLowerCase().includes(q));
  }
  if (packageFilters.wheelDiameter) {
    const d = Number(packageFilters.wheelDiameter);
    if (Number.isFinite(d)) rows = rows.filter((b) => Number(b?.wheel?.diameter) === d);
  }
  if (packageFilters.tireBrand) {
    const q = packageFilters.tireBrand.toLowerCase();
    rows = rows.filter((b) => String(b?.tire?.brand || '').toLowerCase().includes(q));
  }

  const minP = packageFilters.minPrice ? Number(packageFilters.minPrice) : null;
  const maxP = packageFilters.maxPrice ? Number(packageFilters.maxPrice) : null;
  if (Number.isFinite(minP)) rows = rows.filter((b) => getTotal(b) >= minP);
  if (Number.isFinite(maxP)) rows = rows.filter((b) => getTotal(b) <= maxP);

  return rows;
}, [packageBundles, packageFilters]);

