  border: 1px solid rgba(255, 255, 255, 0.10);
  border-radius: 14px;
  overflow: hidden;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.45);
}

.vizHeader {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 14px 16px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.08);
}

.vizTitle {
  font-weight: 900;
  font-size: 16px;
  color: #fff;
}

.vizStage {
  position: relative;
  background: radial-gradient(1200px 400px at 50% 30%, rgba(255, 255, 255, 0.08), rgba(255, 255, 255, 0.02));
  padding: 16px;
}

.vizVehicle {
  width: 100%;
  height: auto;
  display: block;
  border-radius: 10px;
}

.vizWheel {
  position: absolute;
  transform: translate(-50%, -50%);
  object-fit: contain;
  filter: drop-shadow(0 10px 14px rgba(0, 0, 0, 0.45));
  pointer-events: none;
}

.vizFooter {
  padding: 12px 16px;
  border-top: 1px solid rgba(255, 255, 255, 0.08);
}
